import{_ as o,o as a,c as r,a3 as e}from"./chunks/framework.DACwFHq9.js";const g=JSON.parse('{"title":"内容查重","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/content-deduplicator.md","filePath":"user-guide/tools/content-deduplicator.md","lastUpdated":1778221347000}'),l={name:"user-guide/tools/content-deduplicator.md"};function d(i,t,n,s,h,c){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="内容查重" tabindex="-1">内容查重 <a class="header-anchor" href="#内容查重" aria-label="Permalink to &quot;内容查重&quot;">​</a></h1><blockquote><p>快速扫描目录中的重复文本文件，支持精确匹配、规范化匹配和模糊匹配，帮助您发现并清理冗余内容。</p></blockquote><hr><h2 id="功能概览" tabindex="-1">功能概览 <a class="header-anchor" href="#功能概览" aria-label="Permalink to &quot;功能概览&quot;">​</a></h2><ul><li><strong>四种预设模式</strong>：针对不同场景（日常文档、精确查重、代码库、文本文档）提供一键配置</li><li><strong>三级匹配粒度</strong>：精确匹配（逐字节一致）、规范化匹配（忽略空白/大小写）、模糊匹配（阈值可控）</li><li><strong>实时进度展示</strong>：五阶段扫描流程 + 当前处理文件提示，大目录也不焦虑</li><li><strong>可视化对比</strong>：内置双栏文件内容对比面板，对比冗余文件差异</li><li><strong>批量清理</strong>：选中冗余文件一键移入回收站，支持按组/按文件精细选择</li></ul><hr><h2 id="快速上手" tabindex="-1">快速上手 <a class="header-anchor" href="#快速上手" aria-label="Permalink to &quot;快速上手&quot;">​</a></h2><h3 id="基本流程" tabindex="-1">基本流程 <a class="header-anchor" href="#基本流程" aria-label="Permalink to &quot;基本流程&quot;">​</a></h3><ol><li>在左侧 <strong>查重配置</strong> 面板中选择一个 <strong>快速预设</strong></li><li>输入或拖拽要扫描的 <strong>目录路径</strong></li><li>点击 <strong>开始扫描</strong>，等待扫描完成</li><li>在右侧 <strong>扫描结果</strong> 中查看重复文件组，展开查看详情</li><li>勾选需要清理的冗余文件，点击 <strong>删除选中</strong> 移入回收站</li></ol><h3 id="场景举例" tabindex="-1">场景举例 <a class="header-anchor" href="#场景举例" aria-label="Permalink to &quot;场景举例&quot;">​</a></h3><p><strong>场景：清理 LLM 生成的重复对话记录</strong></p><ol><li>选择预设「宽松模式」— 它会忽略空白和标点差异，适合 LLM 生成内容</li><li>拖拽存放对话记录的文件夹到扫描路径输入框</li><li>点击「开始扫描」</li><li>扫描完成后，按「浪费空间」排序，优先处理占用空间大的重复组</li><li>全选冗余文件，一键删除</li></ol><hr><h2 id="功能详解" tabindex="-1">功能详解 <a class="header-anchor" href="#功能详解" aria-label="Permalink to &quot;功能详解&quot;">​</a></h2><h3 id="匹配模式" tabindex="-1">匹配模式 <a class="header-anchor" href="#匹配模式" aria-label="Permalink to &quot;匹配模式&quot;">​</a></h3><p>内容查重引擎提供三种匹配粒度，按匹配难度递增排列：</p><table tabindex="0"><thead><tr><th>匹配类型</th><th>说明</th><th>典型用途</th></tr></thead><tbody><tr><td><strong>精确匹配</strong></td><td>文件内容逐字节完全一致</td><td>直接复制的文件</td></tr><tr><td><strong>规范化匹配</strong></td><td>忽略空白、标点、大小写等格式差异后一致</td><td>LLM 输出、重新排版后的文档</td></tr><tr><td><strong>模糊匹配</strong></td><td>内容高度相似（相似度 ≥ 阈值）但不完全一致</td><td>模板填充、版本迭代中的小改版</td></tr></tbody></table><p>扫描结果中，每个重复组会标注其匹配类型（&quot;精确&quot;或&quot;规范化&quot;），方便您判断清理优先级。</p><h3 id="预设模式详解" tabindex="-1">预设模式详解 <a class="header-anchor" href="#预设模式详解" aria-label="Permalink to &quot;预设模式详解&quot;">​</a></h3><table tabindex="0"><thead><tr><th>预设</th><th>适用场景</th><th>关键行为</th></tr></thead><tbody><tr><td><strong>宽松模式</strong></td><td>LLM 生成文本、文档去重</td><td>忽略空白 + 标点 + 大小写，尺寸阈值 10%</td></tr><tr><td><strong>严格模式</strong></td><td>精确查重、版权检查</td><td>仅忽略空白，保留大小写，尺寸阈值 5%</td></tr><tr><td><strong>代码模式</strong></td><td>代码库去重、检测代码拷贝</td><td>仅扫描代码扩展名，保留缩进换行，区分大小写</td></tr><tr><td><strong>文档模式</strong></td><td>Markdown / TXT 文档去重</td><td>仅扫描文档扩展名，忽略空白和大小写</td></tr></tbody></table><p>选择预设后，所有配置项会自动填充，您也可以在「高级选项」中进一步微调。</p><h3 id="扫描流程与进度" tabindex="-1">扫描流程与进度 <a class="header-anchor" href="#扫描流程与进度" aria-label="Permalink to &quot;扫描流程与进度&quot;">​</a></h3><p>扫描过程分为五个阶段，面板会实时显示当前阶段的进度：</p><ol><li><strong>收集文件</strong> — 遍历目录，收集所有文本文件</li><li><strong>尺寸过滤</strong> — 快速过滤掉尺寸差异过大的文件对</li><li><strong>快速指纹</strong> — 基于文件头部内容生成指纹，粗筛候选对</li><li><strong>全文哈希</strong> — 对候选对进行全文哈希比对，确定匹配</li><li><strong>构建结果</strong> — 整理重复组，生成统计信息</li></ol><p>扫描过程中，面板会实时显示「已发现 X 组」重复，无需等待扫描完全结束即可了解大致情况。</p><h3 id="结果面板操作" tabindex="-1">结果面板操作 <a class="header-anchor" href="#结果面板操作" aria-label="Permalink to &quot;结果面板操作&quot;">​</a></h3><p>扫描完成后，右侧结果面板提供丰富的操作：</p><ul><li><strong>搜索文件名</strong> — 输入关键字快速定位特定重复组</li><li><strong>筛选匹配类型</strong> — 只查看精确匹配或规范化匹配的组</li><li><strong>排序方式</strong> — 按浪费空间 / 相似度 / 文件数排序</li><li><strong>展开查看</strong> — 点击重复组，展开查看组内所有文件</li><li><strong>文件对比</strong> — 点击相似文件旁的对比按钮，在弹窗中对比两个文件内容</li><li><strong>精细选择</strong> — 在组内逐一勾选需要清理的冗余文件</li></ul><p>每组中有一个 <strong>代表文件</strong>（带有皇冠图标），它是该组中最早或最完整的文件，对比和删除时以此为参照。</p><h3 id="文件删除" tabindex="-1">文件删除 <a class="header-anchor" href="#文件删除" aria-label="Permalink to &quot;文件删除&quot;">​</a></h3><p>删除操作会将选中的文件 <strong>移入系统回收站</strong>，不会永久删除，您可以随时从回收站恢复。删除后，结果面板会自动移除已删除的文件并更新统计信息。</p><hr><h2 id="高级用法" tabindex="-1">高级用法 <a class="header-anchor" href="#高级用法" aria-label="Permalink to &quot;高级用法&quot;">​</a></h2><h3 id="自定义配置" tabindex="-1">自定义配置 <a class="header-anchor" href="#自定义配置" aria-label="Permalink to &quot;自定义配置&quot;">​</a></h3><p>在「高级选项」中，您可以微调扫描参数：</p><table tabindex="0"><thead><tr><th>参数</th><th>说明</th><th>推荐值</th></tr></thead><tbody><tr><td><strong>扩展名白名单</strong></td><td>只扫描指定扩展名的文件，留空扫描所有文本文件</td><td>如 <code>ts,js,vue,py</code></td></tr><tr><td><strong>忽略模式</strong></td><td>Glob 忽略模式，跳过不需要的目录</td><td>默认已含 <code>node_modules</code>、<code>.git</code> 等</td></tr><tr><td><strong>最大文件大小</strong></td><td>超过此大小的文件跳过扫描</td><td>默认 50 MB</td></tr><tr><td><strong>尺寸差异阈值</strong></td><td>文件大小差异超过此比例的不予比对</td><td>默认 5%，宽松模式 10%</td></tr></tbody></table><h3 id="通过-ai-助手调用" tabindex="-1">通过 AI 助手调用 <a class="header-anchor" href="#通过-ai-助手调用" aria-label="Permalink to &quot;通过 AI 助手调用&quot;">​</a></h3><p>内容查重工具注册了 <code>scanDuplicates</code> 方法，AI 助手可以直接调用。例如：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请扫描 D:\\projects\\my-app\\src 目录下的重复代码，使用代码模式。</span></span></code></pre></div><p>AI 助手会自动调用查重引擎并返回格式化结果，包含扫描统计和重复组摘要。</p><h3 id="规范化选项详解" tabindex="-1">规范化选项详解 <a class="header-anchor" href="#规范化选项详解" aria-label="Permalink to &quot;规范化选项详解&quot;">​</a></h3><p>四个规范化选项控制匹配时的&quot;宽容度&quot;：</p><ul><li><strong>忽略空白字符</strong> — <code>true</code> 时，<code>foo bar</code> 和 <code>foobar</code> 视为相同</li><li><strong>忽略标点符号</strong> — <code>true</code> 时，<code>你好！</code> 和 <code>你好 </code> 视为相同</li><li><strong>区分大小写</strong> — <code>false</code> 时，<code>Hello</code> 和 <code>hello</code> 视为相同</li><li><strong>保留换行结构</strong> — 代码模式下建议开启，文档模式下关闭</li></ul><hr><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="扫描结果中显示了很多-跳过文件-是什么意思" tabindex="-1">扫描结果中显示了很多&quot;跳过文件&quot;，是什么意思？ <a class="header-anchor" href="#扫描结果中显示了很多-跳过文件-是什么意思" aria-label="Permalink to &quot;扫描结果中显示了很多&quot;跳过文件&quot;，是什么意思？&quot;">​</a></h3><p>扫描过程中，某些文件会因为以下原因被跳过：</p><ul><li>文件大小超过「最大文件大小」限制</li><li>文件不在「扩展名白名单」中</li><li>文件路径匹配了「忽略模式」</li><li>文件不是文本文件（二进制文件）</li></ul><p>跳过的文件会列在结果面板底部，您可以查看具体原因并根据需要调整配置。</p><h3 id="为什么有些重复文件被标记为-规范化-而不是-精确" tabindex="-1">为什么有些重复文件被标记为&quot;规范化&quot;而不是&quot;精确&quot;？ <a class="header-anchor" href="#为什么有些重复文件被标记为-规范化-而不是-精确" aria-label="Permalink to &quot;为什么有些重复文件被标记为&quot;规范化&quot;而不是&quot;精确&quot;？&quot;">​</a></h3><p>&quot;精确匹配&quot;要求文件内容逐字节一致，而&quot;规范化匹配&quot;是在忽略空白、标点、大小写等格式差异后判定为相同的。如果两个文件只是在排版格式上有细微差异（比如缩进风格不同、行尾空格不同），就会被列为规范化匹配。</p><h3 id="我可以同时清理多个目录吗" tabindex="-1">我可以同时清理多个目录吗？ <a class="header-anchor" href="#我可以同时清理多个目录吗" aria-label="Permalink to &quot;我可以同时清理多个目录吗？&quot;">​</a></h3><p>当前版本一次只扫描一个目录。如果需要清理多个目录，可以分多次扫描。如果多个目录内容存在交叉重复，建议先将它们合并到一个父目录中再进行扫描。</p><h3 id="删除的文件去哪了" tabindex="-1">删除的文件去哪了？ <a class="header-anchor" href="#删除的文件去哪了" aria-label="Permalink to &quot;删除的文件去哪了？&quot;">​</a></h3><p>所有删除操作都是 <strong>移入系统回收站</strong>，不会永久删除文件。如果您误删了文件，可以打开系统回收站还原。如果需要永久删除，请在回收站中执行二次清理。</p><h3 id="扫描速度慢怎么办" tabindex="-1">扫描速度慢怎么办？ <a class="header-anchor" href="#扫描速度慢怎么办" aria-label="Permalink to &quot;扫描速度慢怎么办？&quot;">​</a></h3><p>影响扫描速度的主要因素：</p><ul><li><strong>文件数量</strong>：文件越多，扫描越慢。建议排除 <code>node_modules</code> 等大型目录</li><li><strong>文件大小</strong>：大文件的全文哈希耗时较长，可降低「最大文件大小」限制</li><li><strong>匹配精度</strong>：模糊匹配比精确匹配慢，如追求速度可使用严格模式</li></ul><p>如果扫描长时间无响应，可以点击「停止扫描」中断操作，调整配置后重试。</p>',59)])])}const p=o(l,[["render",d]]);export{g as __pageData,p as default};
